import { useMemo } from "react";
export function useFiltered(leafs, filter) {
    const filtered = useMemo(() => {
        if (!filter)
            return null;
        const filtered = [];
        for (let i = 0; i < leafs.length; i++) {
            const node = leafs[i];
            if (filter(node))
                filtered.push(i);
        }
        return filtered;
    }, [filter, leafs]);
    return filtered;
}
